game.initial-sql-script:
DROP TABLE IF EXISTS inhabitant; DROP TABLE IF EXISTS village;
CREATE TABLE village ( id INTEGER PRIMARY KEY, name TEXT NOT NULL, population INTEGER NOT NULL );
CREATE TABLE inhabitant ( id INTEGER PRIMARY KEY, name TEXT NOT NULL, village_id INTEGER NOT NULL REFERENCES village(id), profession TEXT NOT NULL, gold INTEGER NOT NULL, reputation INTEGER NOT NULL );
INSERT INTO village (id, name, population) VALUES (1, 'Oakheart', 120), (2, 'Mooncliff', 95), (3, 'Emberfall', 120), (4, 'Tidewatch', 70);
INSERT INTO inhabitant (id, name, village_id, profession, gold, reputation) VALUES (1, 'Ayla', 1, 'Scout', 250, 88), (2, 'Borin', 2, 'Blacksmith', 400, 91), (3, 'Cyra', 3, 'Ranger', 400, 91), (4, 'Daro', 1, 'Hunter', 180, 77), (5, 'Elin', 4, 'Healer', 320, 95), (6, 'Fynn', 2, 'Trader', 250, 88), (7, 'Gala', 3, 'Scholar', 150, 70), (8, 'Hiro', 4, 'Captain', 500, 99), (9, 'Ivo', 1, 'Inventor', 320, 95), (10, 'Juno', 4, 'Fisher', 90, 60);
